import{c as t,Q as a,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Code as Agent Harness","description":"","frontmatter":{"title":"Code as Agent Harness","authors":"Xuying Ning, Katherine Tieu, Dongqi Fu, Tianxin Wei, Zihao Li, Yuanchen Bei, et al.","published":"2026-05-18T00:00:00.000Z","source":"https://arxiv.org/abs/2605.18747"},"headers":[],"relativePath":"research/agent-harness/references/2026-05-18-code-as-agent-harness-2605-18747.md","filePath":"research/agent-harness/references/2026-05-18-code-as-agent-harness-2605-18747.md","lastUpdated":1779901665000}'),s={name:"research/agent-harness/references/2026-05-18-code-as-agent-harness-2605-18747.md"};function i(o,e,l,d,c,g){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="code-as-agent-harness" tabindex="-1">Code as Agent Harness <a class="header-anchor" href="#code-as-agent-harness" aria-label="Permalink to &quot;Code as Agent Harness&quot;">​</a></h1><p><strong>Authors</strong>: Xuying Ning, Katherine Tieu, Dongqi Fu, Tianxin Wei, Zihao Li, Yuanchen Bei, et al. (42 total; affiliations: UIUC, Meta, Stanford) <strong>Published</strong>: May 18, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.18747" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.18747</a><strong>arXiv ID</strong>: 2605.18747 <strong>Categories</strong>: cs.CL, cs.AI <strong>License</strong>: CC BY 4.0</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Code transitions from merely generated output to &quot;the executable, inspectable, and stateful medium through which agents reason, act, and adapt.&quot; The paper proposes organizing code-centric agent design across three layers: harness interfaces (reasoning, acting, environment modeling), harness mechanisms (planning, memory, tool use, feedback-driven control), and multi-agent orchestration over shared code artifacts. Applications span coding assistants, GUI/OS automation, embodied agents, scientific discovery, personalization, DevOps, and enterprise workflows.</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>Code is no longer just a product agents emit—it is the <strong>operational substrate</strong> that connects models to their environments. The paper introduces the concept of <strong>&quot;code as agent harness&quot;</strong>: executable programs become the connective tissue enabling reliable, verifiable, and stateful autonomous systems.</p><p>A critical distinction the authors make:</p><table tabindex="0"><thead><tr><th>Component</th><th>Definition</th></tr></thead><tbody><tr><td>Model-internal capabilities</td><td>LLM reasoning and perception abilities</td></tr><tr><td>System harness infrastructure</td><td>Predefined tools, APIs, memory systems, validators</td></tr><tr><td>Agent-initiated code artifacts</td><td>Interactive programs agents create, execute, and share during task execution</td></tr></tbody></table><hr><h2 id="three-layer-architecture" tabindex="-1">Three-Layer Architecture <a class="header-anchor" href="#three-layer-architecture" aria-label="Permalink to &quot;Three-Layer Architecture&quot;">​</a></h2><h3 id="layer-1-harness-interface" tabindex="-1">Layer 1: Harness Interface <a class="header-anchor" href="#layer-1-harness-interface" aria-label="Permalink to &quot;Layer 1: Harness Interface&quot;">​</a></h3><p>Code serves three functions connecting agents to the world:</p><p><strong>Code for Reasoning</strong></p><ul><li>Program-delegated reasoning: offload computation to executable programs (PAL-style)</li><li>Formal verification: symbolic solvers and proof assistants (Lean-based theorem proving)</li><li>Iterative code-grounded refinement: execution traces as verification signals</li></ul><p><strong>Code for Acting</strong></p><ul><li>Executable policies and skill interfaces ground high-level intent in environments</li><li>Embodied agents: robot control policies (CaP, RoboCodeX)</li><li>GUI/OS agents: DOM-grounded command synthesis</li><li>Software agents: patch generation, issue resolution</li></ul><p><strong>Code for Environment</strong></p><ul><li>Program states, repositories, tests, and simulators represent world dynamics</li><li>Executable feedback signals replace pure language-based environment descriptions</li><li>Test suites as grounded success criteria</li></ul><h3 id="layer-2-harness-mechanisms" tabindex="-1">Layer 2: Harness Mechanisms <a class="header-anchor" href="#layer-2-harness-mechanisms" aria-label="Permalink to &quot;Layer 2: Harness Mechanisms&quot;">​</a></h3><p>Four mechanisms sustain long-horizon agent operation:</p><p><strong>Planning</strong></p><ul><li>Linear decomposition: sequential subtask chains</li><li>Structure-grounded: dependency graphs and DAG-based execution</li><li>Search-based: tree search over candidate plans (MCTS variants)</li><li>Orchestration-driven: planner delegates to specialized executor agents</li></ul><p><strong>Memory</strong></p><ul><li>Working memory: active task state and intermediate results</li><li>Semantic memory: reusable code patterns and API knowledge</li><li>Experiential memory: success/failure history (Voyager-style skill libraries)</li><li>Long-term shared context: persistent interaction logs</li></ul><p><strong>Tool Use</strong></p><ul><li>API connectors: external service integration</li><li>Verification systems: test runners, linters, type checkers</li><li>Workflow environments: CI/CD pipelines, sandboxed execution</li></ul><p><strong>Feedback-Driven Control</strong></p><ul><li>Plan–execute–verify loops</li><li>Execution outcome detection for failure attribution</li><li>Corrective revision triggered by runtime signals</li></ul><h3 id="layer-3-scaling-the-harness" tabindex="-1">Layer 3: Scaling the Harness <a class="header-anchor" href="#layer-3-scaling-the-harness" aria-label="Permalink to &quot;Layer 3: Scaling the Harness&quot;">​</a></h3><p>Multi-agent coordination over shared code artifacts:</p><ul><li><strong>Shared repositories</strong> as synchronization primitives</li><li><strong>Role specialization</strong>: synthesizer, reviewer, verifier, planner agents</li><li><strong>Interaction modes</strong>: collaborative synthesis + adversarial validation</li><li><strong>Convergence mechanisms</strong>: resolving conflicts in distributed agent edits</li><li><strong>Synchronized execution feedback</strong>: consistent state across agents (AutoGen, MetaGPT patterns)</li></ul><hr><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Domain</th><th>Code Harness Role</th></tr></thead><tbody><tr><td>Code Assistance</td><td>Autonomous patches, tests, issue resolution</td></tr><tr><td>GUI/OS Automation</td><td>Interface command synthesis grounded in DOM trees</td></tr><tr><td>Scientific Discovery</td><td>Hypothesis-testing pipelines spanning simulations and analysis</td></tr><tr><td>Embodied Agents</td><td>Executable robot policies and skill libraries</td></tr><tr><td>Personalization / Recommendation</td><td>Adaptive user-preference policies</td></tr><tr><td>DevOps</td><td>CI/CD automation, infrastructure as code</td></tr><tr><td>Enterprise Workflows</td><td>Multi-agent process orchestration</td></tr></tbody></table><hr><h2 id="open-challenges" tabindex="-1">Open Challenges <a class="header-anchor" href="#open-challenges" aria-label="Permalink to &quot;Open Challenges&quot;">​</a></h2><p>Seven major unsolved problems identified:</p><ol><li><strong>Evaluation beyond task completion</strong>: metrics capturing reasoning quality, not just outputs</li><li><strong>Semantic verification under incomplete execution feedback</strong>: partial or noisy execution traces</li><li><strong>Regression prevention during iterative harness improvement</strong>: preserving capabilities while evolving infrastructure</li><li><strong>Multi-agent shared state consistency</strong>: distributed agents editing the same codebase</li><li><strong>Human oversight in safety-critical deployments</strong>: intervention points and authority boundaries</li><li><strong>Multimodal environment extension</strong>: integrating vision, audio, and embodied sensing</li><li><strong>Principled science of harness engineering</strong>: moving from ad-hoc to systematic harness design</li></ol><hr><h2 id="key-systems-referenced" tabindex="-1">Key Systems Referenced <a class="header-anchor" href="#key-systems-referenced" aria-label="Permalink to &quot;Key Systems Referenced&quot;">​</a></h2><table tabindex="0"><thead><tr><th>System</th><th>Contribution</th></tr></thead><tbody><tr><td>PAL</td><td>Program-aided reasoning (code as computation delegator)</td></tr><tr><td>Lean / Isabelle</td><td>Formal proof assistants (symbolic verification)</td></tr><tr><td>CaP, RoboCodeX</td><td>Programmatic policy generation for robotics</td></tr><tr><td>Voyager</td><td>Lifelong learning via executable skill libraries</td></tr><tr><td>AutoGen</td><td>Multi-agent coordination framework</td></tr><tr><td>MetaGPT</td><td>Role-specialized multi-agent software development</td></tr></tbody></table><hr><h2 id="relevance-to-harness-engineering" tabindex="-1">Relevance to Harness Engineering <a class="header-anchor" href="#relevance-to-harness-engineering" aria-label="Permalink to &quot;Relevance to Harness Engineering&quot;">​</a></h2><p>This survey directly addresses the conceptual foundations underlying the workspace&#39;s harness-engineering practice:</p><ul><li><strong>Three-layer framing</strong> (Interface / Mechanisms / Scaling) maps onto the workspace&#39;s Body + Harness + Agent topology</li><li><strong>Feedback-driven control</strong> validates the PGE (Planner–Generator–Evaluator) separation in <code>harness-engineering.md</code></li><li><strong>Verification as runtime capability</strong> (not post-hoc check) aligns with R4 Goal-Driven and R12 Fail Loud rules</li><li><strong>Regression prevention</strong> directly addresses the Ratchet upgrade path and K×M scoring framework</li><li><strong>Multi-agent state consistency</strong> is the theoretical grounding for fan-out topology rules (max 4 sub-agents, parent↔child only)</li></ul>',47)])])}const p=t(s,[["render",i]]);export{u as __pageData,p as default};
